import re

def slug(text):
    return "-".join(re.split(r'\s+', text.strip().lower()))

def build_index(labels):
    index = {}
    for label in labels:
        slug_val = slug(label)
        if slug_val not in index:
            index[slug_val] = []
        index[slug_val].append(label)
    return index

